102	// Select the appropriate Slack token for read/write operations.
103	function getTokenForOperation(
104	  account: ResolvedSlackAccount,
105	  operation: "read" | "write",
106	): string | undefined {
107	  const userToken = account.config.userToken?.trim() || undefined;
108	  const botToken = account.botToken?.trim();
109	  const allowUserWrites = account.config.userTokenReadOnly === false;
110	  if (operation === "read") {
111	    return userToken ?? botToken;
112	  }
113	  if (!allowUserWrites) {
114	    return botToken;
115	  }
116	  return botToken ?? userToken;
117	}
