import { createChatChannelPlugin, getChatChannelMeta } from "openclaw/plugin-sdk/core";
import type { PulseBoardConfig } from "./types.js";

// Resolved account shape for a PulseBoard connection
type ResolvedPulseBoardAccount = {
  accountId: string;
  configured: boolean;
  boardUrl: string;
  apiToken: string;
  username: string;
};

// Meta is populated from the plugin manifest at runtime once "pulseboard" is
// registered in the core channel registry; the cast is intentional here.
// eslint-disable-next-line @typescript-eslint/no-explicit-any
const baseMeta = getChatChannelMeta("pulseboard" as any);

export const pulseBoardPlugin = createChatChannelPlugin<ResolvedPulseBoardAccount>({
  base: {
    id: "pulseboard",
    meta: {
      ...baseMeta,
      label: "PulseBoard",
      docsPath: "/channels/pulseboard",
      blurb: "Real-time bulletin board messaging with named boards and direct messages.",
    },
    capabilities: {
      chatTypes: ["direct", "group"],
      media: false,
    },
    reload: { configPrefixes: ["channels.pulseboard"] },
    config: {
      listAccountIds: (_cfg) => {
        // Stub: return "default" if any account is configured
        const pbCfg = (_cfg?.channels as Record<string, unknown> | undefined)
          ?.pulseboard as PulseBoardConfig | undefined;
        const ids = Object.keys(pbCfg?.accounts ?? {});
        return ids.length > 0 ? ids : ["default"];
      },
      resolveAccount: ({ cfg, accountId }) => {
        const pbCfg = (cfg?.channels as Record<string, unknown> | undefined)
          ?.pulseboard as PulseBoardConfig | undefined;
        const id = accountId ?? "default";
        const account = pbCfg?.accounts?.[id];
        return {
          accountId: id,
          configured: Boolean(account?.boardUrl && account?.apiToken),
          boardUrl: account?.boardUrl ?? "",
          apiToken: account?.apiToken ?? "",
          username: account?.username ?? "",
        };
      },
      defaultAccountId: (cfg) => {
        const pbCfg = (cfg?.channels as Record<string, unknown> | undefined)
          ?.pulseboard as PulseBoardConfig | undefined;
        const ids = Object.keys(pbCfg?.accounts ?? {});
        return ids[0] ?? "default";
      },
      isConfigured: (account) => account.configured,
    },
    setup: {
      applyAccountConfig: async (_opts) => {
        // stub: account config is applied via direct config file edits
      },
    },
    messaging: {
      normalizeTarget: (target) => target.trim(),
    },
    gateway: {
      startAccount: async (ctx) => {
        ctx.log?.info(
          `[${ctx.accountId}] connecting to PulseBoard at ${ctx.account.boardUrl || "(unconfigured)"}`,
        );
        // stub: real implementation would open a WebSocket/long-poll connection
      },
    },
  },
  outbound: {
    deliveryMode: "direct",
    textChunkLimit: 4000,
    sendText: async ({ to }) => ({
      channel: "pulseboard",
      to,
      messageId: `pb-${Date.now()}`,
    }),
  },
});

